const checkpoints = [];
const services = JSON.parse(localStorage.getItem('services') || '[]');
const quoteRequests = JSON.parse(localStorage.getItem('quote_requests') || '[]');

// Candidate services: ongoing lawn mowing, monthly, small yard, under $120, supports quote, lawn mowing feature
const candidateServices = services.filter(s => {
  if (!s || !s.isActive) return false;
  if (s.serviceType !== 'ongoing_lawn_mowing') return false;
  if (s.priceUnit !== 'per_month') return false;
  if (typeof s.basePrice !== 'number' || s.basePrice > 120) return false;
  const sizes = Array.isArray(s.availablePropertySizes) ? s.availablePropertySizes : [];
  if (!sizes.includes('small_up_to_quarter_acre')) return false;
  const feats = Array.isArray(s.featureCodes) ? s.featureCodes : [];
  if (!feats.includes('lawn_mowing')) return false;
  if (s.supportsQuoteRequest !== true) return false;
  return true;
});

let cp1Passed = false; // At least one quote request for a qualifying service with correct small yard & price cap
let cp2Passed = false; // That request uses a highest-rated qualifying service

if (candidateServices.length > 0 && quoteRequests.length > 0) {
  const qualifyingRequests = quoteRequests.filter(q => {
    if (!q) return false;
    const svc = candidateServices.find(s => s.id === q.serviceId);
    if (!svc) return false;
    if (q.propertySizeCode !== 'small_up_to_quarter_acre') return false;
    if (typeof q.maxMonthlyPrice !== 'number' || q.maxMonthlyPrice > 120) return false;
    return true;
  });

  cp1Passed = qualifyingRequests.length > 0;

  if (cp1Passed) {
    let maxRating = -Infinity;
    candidateServices.forEach(s => {
      const r = typeof s.rating === 'number' ? s.rating : 0;
      if (r > maxRating) maxRating = r;
    });
    const topServices = candidateServices.filter(s => (s.rating || 0) === maxRating);
    cp2Passed = qualifyingRequests.some(q => topServices.some(s => s.id === q.serviceId));
  }
}

checkpoints.push({ passed: cp1Passed, weight: 0.5 });
checkpoints.push({ passed: cp2Passed, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const services = JSON.parse(localStorage.getItem('services') || '[]');
const bookings = JSON.parse(localStorage.getItem('bookings') || '[]');
const timeSlots = JSON.parse(localStorage.getItem('time_slots') || '[]');

const springServices = services.filter(s => s && s.serviceType === 'spring_yard_cleanup_one_time' && s.isBookableOnline);
let cp1 = false; // Correct service, date, and pay-on-site
let cp2 = false; // Chosen slot is earliest starting at or after 3 PM

if (springServices.length > 0 && bookings.length > 0) {
  const serviceId = springServices[0].id;
  const targetBookings = bookings.filter(b => {
    if (!b || b.serviceId !== serviceId) return false;
    const dateStr = (b.scheduledDate || '').slice(0, 10);
    if (dateStr !== '2026-03-15') return false;
    if (b.paymentOption !== 'pay_on_site') return false;
    return true;
  });

  cp1 = targetBookings.length > 0;

  if (cp1 && timeSlots.length > 0) {
    const daySlots = timeSlots
      .filter(ts => {
        if (!ts || ts.serviceId !== serviceId) return false;
        const dStr = (ts.date || '').slice(0, 10);
        if (dStr !== '2026-03-15') return false;
        const start = ts.startTime || '';
        // Consider all slots on that date whose start is at or after 3 PM
        return start >= '2026-03-15T15:00:00Z';
      })
      .sort((a, b) => (a.startTime || '').localeCompare(b.startTime || ''));

    const earliest = daySlots[0] || null;
    if (earliest) {
      cp2 = targetBookings.some(b => b.timeSlotId === earliest.id);
    }
  }
}

checkpoints.push({ passed: cp1, weight: 0.5 });
checkpoints.push({ passed: cp2, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const packages = JSON.parse(localStorage.getItem('custom_packages') || '[]');
const items = JSON.parse(localStorage.getItem('custom_package_service_items') || '[]');
const services = JSON.parse(localStorage.getItem('services') || '[]');

let cp1 = false; // Package with exactly 3 services: mowing, hedge trimming, mulching with correct frequencies
let cp2 = false; // Same package has total and target range between $300–$400 and is finalized for review

if (packages.length > 0 && items.length > 0 && services.length > 0) {
  packages.forEach(pkg => {
    if (!pkg) return;
    const pkgItems = items.filter(it => it && it.packageId === pkg.id);
    if (pkgItems.length !== 3) return;

    const detailedItems = pkgItems
      .map(it => ({ item: it, service: services.find(s => s && s.id === it.serviceId) || null }))
      .filter(x => x.service);

    if (detailedItems.length !== 3) return;

    let hasMowing = false;
    let hasHedge = false;
    let hasMulch = false;
    let mowingFreqOk = false;
    let hedgeFreqOk = false;
    let mulchFreqOk = false;

    detailedItems.forEach(({ item, service }) => {
      const feats = Array.isArray(service.featureCodes) ? service.featureCodes : [];
      if (feats.includes('lawn_mowing')) {
        hasMowing = true;
        if (item.frequency === 'every_2_weeks') mowingFreqOk = true;
      }
      if (feats.includes('hedge_trimming')) {
        hasHedge = true;
        if (item.frequency === 'once_per_month') hedgeFreqOk = true;
      }
      if (feats.includes('flower_bed_mulching')) {
        hasMulch = true;
        if (item.frequency === 'one_time') mulchFreqOk = true;
      }
    });

    const servicesOk = hasMowing && hasHedge && hasMulch;
    const freqOk = mowingFreqOk && hedgeFreqOk && mulchFreqOk;

    if (servicesOk && freqOk) {
      cp1 = true;
      const total = typeof pkg.totalEstimatedPrice === 'number' ? pkg.totalEstimatedPrice : 0;
      const totalOk = total >= 300 && total <= 400;
      const hasTargets = typeof pkg.targetPriceMin === 'number' && typeof pkg.targetPriceMax === 'number';
      const targetRangeOk = hasTargets && pkg.targetPriceMin <= 300 && pkg.targetPriceMax >= 400;
      const statusOk = pkg.status === 'saved' || pkg.status === 'ready_for_checkout';
      if (totalOk && targetRangeOk && statusOk) {
        cp2 = true;
      }
    }
  });
}

checkpoints.push({ passed: cp1, weight: 0.5 });
checkpoints.push({ passed: cp2, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const plans = JSON.parse(localStorage.getItem('maintenance_plans') || '[]');
const carts = JSON.parse(localStorage.getItem('cart') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');
const orders = JSON.parse(localStorage.getItem('orders') || '[]');

const candidatePlans = plans.filter(p => {
  if (!p || !p.isActive) return false;
  if (p.planType !== 'residential') return false;
  if (!p.includesLawnMowing || !p.includesLeafRemoval) return false;
  if (typeof p.pricePerMonth !== 'number' || p.pricePerMonth > 150) return false;
  return true;
});

let cp1 = false; // Cart has the best qualifying plan with monthly billing
let cp2 = false; // Checkout order created that includes that best plan with monthly billing

if (candidatePlans.length > 0) {
  let maxVisits = -Infinity;
  candidatePlans.forEach(p => {
    const v = typeof p.visitsPerMonth === 'number' ? p.visitsPerMonth : 0;
    if (v > maxVisits) maxVisits = v;
  });
  const bestPlans = candidatePlans.filter(p => (p.visitsPerMonth || 0) === maxVisits);
  const bestPlanIds = bestPlans.map(p => p.id);

  const qualifyingCartItem = cartItems.find(ci => {
    if (!ci || ci.sourceType !== 'maintenance_plan') return false;
    if (ci.billingFrequency !== 'monthly') return false;
    if (!bestPlanIds.includes(ci.sourceId)) return false;
    return ci.quantity > 0;
  });

  cp1 = !!qualifyingCartItem;

  if (cp1 && orders.length > 0) {
    cp2 = orders.some(order => {
      if (!order || order.status !== 'pending_payment') return false;
      const items = Array.isArray(order.itemsSnapshot) ? order.itemsSnapshot : [];
      return items.some(it => it.sourceType === 'maintenance_plan' &&
        it.billingFrequency === 'monthly' &&
        bestPlanIds.includes(it.sourceId));
    });
  }
}

checkpoints.push({ passed: cp1, weight: 0.5 });
checkpoints.push({ passed: cp2, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const services = JSON.parse(localStorage.getItem('services') || '[]');
const consultationRequests = JSON.parse(localStorage.getItem('consultation_requests') || '[]');

// Candidate services: drought-tolerant design, price range 200–600, rating >= 4
const candidateServices = services.filter(s => {
  if (!s || !s.isActive) return false;
  const feats = Array.isArray(s.featureCodes) ? s.featureCodes : [];
  if (!feats.includes('drought_tolerant_design')) return false;
  if (typeof s.minPrice !== 'number' || typeof s.maxPrice !== 'number') return false;
  if (s.minPrice < 200 || s.maxPrice > 600) return false;
  if (typeof s.rating !== 'number' || s.rating < 4.0) return false;
  return true;
});

let cp1 = false; // Consultation requested for a highest-rated qualifying drought-tolerant service
let cp2 = false; // The consultation message mentions the front yard

if (candidateServices.length > 0 && consultationRequests.length > 0) {
  let maxRating = -Infinity;
  candidateServices.forEach(s => {
    const r = typeof s.rating === 'number' ? s.rating : 0;
    if (r > maxRating) maxRating = r;
  });
  const topServices = candidateServices.filter(s => (s.rating || 0) === maxRating);
  const topIds = topServices.map(s => s.id);

  const qualifyingRequests = consultationRequests.filter(r => r && topIds.includes(r.serviceId));
  cp1 = qualifyingRequests.length > 0;

  if (cp1) {
    cp2 = qualifyingRequests.some(r => {
      const msg = (r.message || '').toLowerCase();
      return msg.includes('front yard');
    });
  }
}

checkpoints.push({ passed: cp1, weight: 0.7 });
checkpoints.push({ passed: cp2, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const services = JSON.parse(localStorage.getItem('services') || '[]');
const promotions = JSON.parse(localStorage.getItem('promotions') || '[]');
const carts = JSON.parse(localStorage.getItem('cart') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');
const orders = JSON.parse(localStorage.getItem('orders') || '[]');

const mowingService = services.find(s => s && s.serviceType === 'one_time_mowing');
let cp1 = false; // Cart has one-time mowing with correct 10% first-time promo applied
let cp2 = false; // An order in pending_payment status was created from such a cart

if (mowingService && promotions.length > 0 && carts.length > 0 && cartItems.length > 0) {
  const promo = promotions.find(p => {
    if (!p || p.discountType !== 'percentage' || p.discountValue !== 10 || !p.firstTimeCustomerOnly) return false;
    const svcIds = Array.isArray(p.applicableServiceIds) ? p.applicableServiceIds : [];
    return svcIds.includes(mowingService.id);
  });

  if (promo) {
    const qualifyingCarts = carts.filter(cart => {
      if (!cart) return false;
      const code = (cart.promotionCode || '').trim().toLowerCase();
      const promoCode = (promo.promoCode || '').trim().toLowerCase();
      if (!code || code !== promoCode) return false;

      const itemsForCart = cartItems.filter(ci => ci && ci.cartId === cart.id && ci.sourceType === 'service');
      const mowingItem = itemsForCart.find(ci => ci.sourceId === mowingService.id && ci.quantity > 0);
      if (!mowingItem) return false;

      const unitPrice = typeof mowingService.basePrice === 'number' ? mowingService.basePrice : (mowingService.minPrice || 0);
      const expectedSubtotal = unitPrice * mowingItem.quantity;
      const lineSubtotal = typeof mowingItem.lineSubtotal === 'number' ? mowingItem.lineSubtotal : expectedSubtotal;
      const lineDiscount = typeof mowingItem.lineDiscount === 'number' ? mowingItem.lineDiscount : 0;
      const lineTotal = typeof mowingItem.lineTotal === 'number' ? mowingItem.lineTotal : (lineSubtotal - lineDiscount);

      const expectedDiscount = expectedSubtotal * 0.10;
      const expectedTotal = expectedSubtotal - expectedDiscount;
      const eps = 1e-2;
      const discountOk = (Math.abs(lineDiscount - expectedDiscount) < eps) || (Math.abs(lineTotal - expectedTotal) < eps);
      return discountOk;
    });

    cp1 = qualifyingCarts.length > 0;

    if (cp1 && orders.length > 0) {
      const qualifyingCartIds = qualifyingCarts.map(c => c.id);
      cp2 = orders.some(o => o && o.status === 'pending_payment' && qualifyingCartIds.includes(o.cartId));
    }
  }
}

checkpoints.push({ passed: cp1, weight: 0.6 });
checkpoints.push({ passed: cp2, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const projects = JSON.parse(localStorage.getItem('projects') || '[]');
const favArr = JSON.parse(localStorage.getItem('favorite_projects') || '[]');
const designRequests = JSON.parse(localStorage.getItem('project_design_requests') || '[]');

let cp1 = false; // Third qualifying project is in favorites
let cp2 = false; // Design request submitted for that project, message includes its reference code and appropriate type

if (projects.length > 0) {
  const filtered = projects.filter(p => {
    if (!p) return false;
    if (p.spaceType !== 'backyard') return false;
    if (p.yardSizeCode !== 'medium_quarter_to_half_acre') return false;
    const feats = Array.isArray(p.featureCodes) ? p.featureCodes : [];
    return feats.includes('patio') && feats.includes('fire_pit');
  });

  if (filtered.length >= 3) {
    const thirdProject = filtered[2];
    const favRecord = favArr.find(f => f && f.id === 'default_favorites');
    const favIds = favRecord && Array.isArray(favRecord.projectIds) ? favRecord.projectIds : [];

    cp1 = favIds.includes(thirdProject.id);

    if (designRequests.length > 0) {
      cp2 = designRequests.some(r => {
        if (!r || r.projectId !== thirdProject.id) return false;
        const msg = (r.message || '').toUpperCase();
        const ref = (thirdProject.referenceCode || '').toUpperCase();
        const referenceMentioned = ref && msg.includes(ref);
        const typeOk = !r.requestedProjectType || r.requestedProjectType === 'backyard_patio_with_fire_pit';
        return referenceMentioned && typeOk;
      });
    }
  }
}

checkpoints.push({ passed: cp1, weight: 0.4 });
checkpoints.push({ passed: cp2, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const serviceSearchRaw = localStorage.getItem('task8_serviceAreaFAQSearch');
const cancellationSearchRaw = localStorage.getItem('task8_cancellationFAQSearch');
let serviceSearch = null;
let cancellationSearch = null;
try { serviceSearch = serviceSearchRaw ? JSON.parse(serviceSearchRaw) : null; } catch (e) { serviceSearch = null; }
try { cancellationSearch = cancellationSearchRaw ? JSON.parse(cancellationSearchRaw) : null; } catch (e) { cancellationSearch = null; }

const saArticleViewed = localStorage.getItem('task8_serviceAreaFAQArticleViewed');
const cancelArticleViewed = localStorage.getItem('task8_cancellationFAQArticleViewed');
const submissions = JSON.parse(localStorage.getItem('contact_form_submissions') || '[]');

let cp1 = false; // Searched and viewed Service Areas FAQ
let cp2 = false; // Searched and viewed Cancellation Policy FAQ
let cp3 = false; // Submitted contact form asking about 60610 and cancellation policy

if (serviceSearch && Array.isArray(serviceSearch.resultArticleIds)) {
  const hasServiceAreasResult = serviceSearch.resultArticleIds.includes('service_areas');
  const viewedCorrect = saArticleViewed === 'service_areas';
  cp1 = hasServiceAreasResult && viewedCorrect;
}

if (cancellationSearch && Array.isArray(cancellationSearch.resultArticleIds)) {
  const hasCancellationResult = cancellationSearch.resultArticleIds.includes('cancellation_policy');
  const viewedCorrect = cancelArticleViewed === 'cancellation_policy';
  cp2 = hasCancellationResult && viewedCorrect;
}

if (submissions.length > 0) {
  cp3 = submissions.some(s => {
    if (!s || s.subject !== 'service_availability') return false;
    const msgLower = (s.message || '').toLowerCase();
    return msgLower.includes('60610') && msgLower.includes('cancellation');
  });
}

checkpoints.push({ passed: cp1, weight: 0.35 });
checkpoints.push({ passed: cp2, weight: 0.35 });
checkpoints.push({ passed: cp3, weight: 0.30 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
